 1	import type { FC } from 'react';
 2	
 3	import { SecretModel, type V1beta1Plan } from '@kubev2v/types';
 4	import { getGroupVersionKindForModel, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 5	import { Label } from '@patternfly/react-core';
 6	import { getNamespace } from '@utils/crds/common/selectors';
 7	import { getLUKSSecretName, getPlanHasNBDEClevis } from '@utils/crds/plans/selectors';
 8	import { useForkliftTranslation } from '@utils/i18n';
 9	
10	type LUKSSecretLinkProps = {
11	  plan: V1beta1Plan;
12	};
13	
14	const LUKSSecretLink: FC<LUKSSecretLinkProps> = ({ plan }) => {
15	  const { t } = useForkliftTranslation();
16	
17	  const luksSecretName = getLUKSSecretName(plan);
18	  const hasNBDEClevis = getPlanHasNBDEClevis(plan);
19	
20	  if (hasNBDEClevis) {
21	    return (
22	      <Label isCompact data-testid="nbde-clevis-enabled-label">
23	        {t('NBDE/Clevis enabled')}
24	      </Label>
25	    );
26	  }
27	
28	  if (luksSecretName) {
29	    return (
30	      <ResourceLink
31	        groupVersionKind={getGroupVersionKindForModel(SecretModel)}
32	        name={luksSecretName}
33	        namespace={getNamespace(plan)}
34	      />
35	    );
36	  }
37	
38	  return (
39	    <Label isCompact data-testid="no-decryption-keys-label">
40	      {t('No decryption defined')}
41	    </Label>
42	  );
43	};
44	
45	export default LUKSSecretLink;

